#include <iostream>
#include <iomanip>
using namespace std;

class Calculator
{
public:
    int add(int a, int b)
    {
        return a + b;
    }

    float add(float a, float b)
    {
        return a + b;
    }
};

int main()
{
    int a, b;
    float x, y;

    cin >> a >> b;
    cin >> x >> y;

    Calculator c;

    cout << c.add(a, b) << " ";
    cout << fixed << setprecision(3) << c.add(x, y);

    return 0;
}
